var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"PENCIL_MAGICIAN_NPC_NULL","text":{"KOREA":"해, 해치웠나……?","JPN":"や、やっつけた……？","ENG":"D-did we get him...?","TWN":"解、解決掉了嗎……？"},"stage":{"bg":"UNDER","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_MAGICIAN_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L4_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그런 것 같구려. 기사의 증식이 멈췄소.","JPN":"そのようですね。騎士の増殖が止まりました。","ENG":"I think so. The knights have stopped multiplying.","TWN":"好像是這樣。騎士停止增生了。"},"stage":{"bg":"UNDER","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_MAGICIAN_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L5_1","type":"dialog","speaker":"PENCIL_MAGICIAN_NPC_NULL","text":{"KOREA":"다행이다. 시엘이 빨리 마무리해 주지 않았다면 위험했을 거야.","JPN":"よかった。シエルちゃんがすぐにとどめを刺してくれたおかげだよ。","ENG":"That's a relief. It would've been dangerous if Ciel didn't finish him off quickly.","TWN":"太好了。如果不是希爾迅速解決問題，情況會很危險。"},"stage":{"bg":"UNDER","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_MAGICIAN_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L7_1","type":"dialog","speaker":"BORA_PROMISE_NULL_NULL","text":{"KOREA":"공략…… 잘 알아냈네.","JPN":"攻略……よくわかったね。","ENG":"The strategy... You figured it out.","TWN":"攻略方法……你很懂呢。"},"stage":{"bg":"UNDER","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORA_PROMISE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"BORA_PROMISE_NULL_NULL","text":{"KOREA":"굉장히 어려운 구역인데……. 잘해줬어. 모두.","JPN":"とても難しいエリアなのに……よくやった、皆。","ENG":"This is supposed to be a difficult area, but... you did good. Everyone.","TWN":"這是一個非常困難的區域……大家都做得很好。"},"stage":{"bg":"UNDER","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORA_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"RULER_JUNIOR_SPORTS_NULL","text":{"KOREA":"에헤헤, 선배들의 힘이 없었으면 저희들 만으론 무리였을 거예요.","JPN":"えへへ、先輩たちの力がなかったら、私たちだけじゃ倒せなかったですよ。","ENG":"Eh he he. We couldn't have done it without the help from our seniors.","TWN":"嘿嘿，如果沒有前輩們的力量，光靠我們是做不到的。"},"stage":{"bg":"UNDER","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RULER_JUNIOR_SPORTS_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_RA","face":"UNIT_LAUGH"}}}},{"id":"L13_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"UNDER","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_RA","text":{"KOREA":"선배, 괜찮아요? 표정이 어두우신데…….","JPN":"先輩、大丈夫ですか？　顔が暗いです……","ENG":"Naielle, are you okay? You look a little upset...","TWN":"前輩，沒事吧？你臉色看起來不太好……"},"stage":{"bg":"UNDER","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RULER_JUNIOR_SPORTS_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_RA","face":"UNIT_DESPAIR"}}}},{"id":"L18_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NULL","text":{"KOREA":"이건 내가 원했던 게 아냐! 마무리는 내가 하고 싶었다고!","JPN":"これは私が望んでた結果じゃない！　とどめは私が刺したかったのよ！","ENG":"This isn't what I wanted! I was supposed to land the finishing blow!","TWN":"這不是我想要的！我想親手結束這一切！"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"BORA_PROMISE_NULL_NULL","text":{"KOREA":"어째서……?","JPN":"どうして……？","ENG":"But why...?","TWN":"為什麼……？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORA_PROMISE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"BORA_PROMISE_NULL_NULL","text":{"KOREA":"모두와 함께 힘을 모아……. 무사히 이겼잖아.","JPN":"皆と力を合わせて……無事勝てたのに。","ENG":"You won... because everyone worked together.","TWN":"大家齊心協力……不是順利拿下了嗎？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORA_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NULL","text":{"KOREA":"흥, 애초에 파티 같은 거 없어도 나 혼자서도 충분했거든?","JPN":"ふん！　そもそも、パーティーなんか組まなくても1人で十分だったのよ。","ENG":"Hmph! I didn't need a party! I could've done it alone!","TWN":"哼，本來就算沒有小隊，我一個人也足夠了！"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"PENCIL_MAGICIAN_NPC_NULL","text":{"KOREA":"얘는 또 고집부리기 시작하네.","JPN":"また意地張っちゃって……","ENG":"There she goes again.","TWN":"這傢伙又開始固執了。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_MAGICIAN_NPC_NULL","face":"UNIT_HATE"},"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"BORA_PROMISE_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORA_PROMISE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"BORA_PROMISE_NULL_NULL","text":{"KOREA":"파티가 필요 없다는 건……. 동료 없이 싸우겠다는 거야……?","JPN":"パーティーがいらないということは……仲間なしで戦うということ？","ENG":"When you say you don't need a party... are you saying you'd fight without any allies...?","TWN":"不需要隊伍……是說要一個人戰鬥嗎……？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORA_PROMISE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"BORA_PROMISE_NULL_NULL","text":{"KOREA":"그건…… 매우 위험한 생각이야.","JPN":"それは……危険な考え方だよ。","ENG":"That's... a very dangerous idea.","TWN":"那是……非常危險的想法。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORA_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"RULER_JUNIOR_SPORTS_NULL","text":{"KOREA":"맞아요. 검은 기사의 공략도 미카 선배가 알아낸 덕에 돌파할 수 있었잖아요.","JPN":"そうです。黒い騎士の攻略だって、ミカ先輩が気づいたから突破できたじゃないですか。","ENG":"She's right. We were only able to beat the black knight because Mika knew how to beat him.","TWN":"沒錯。黑騎士的攻略方法也是多虧了米卡前輩才發現的。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RULER_JUNIOR_SPORTS_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_RA","face":"UNIT_DESPAIR"}}}},{"id":"L34_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NULL","text":{"KOREA":"난 잡졸들이나 맡고 있었다고, 내가 앞장서고 싶었는데…….","JPN":"私は雑魚を処理しただけで……私が先頭に立ちたかったのに……","ENG":"I had to deal with grunts when I wanted to take the lead...","TWN":"我剛剛只是負責對付小嘍囉，我想衝在最前面……"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"비록 시뮬레이션이지만, 전투에서 그런 마음가짐으론 안된다 생각하오.","JPN":"たとえシミュレーションとは言え、そのような気持ちで戦闘に臨んではいけないと思います。","ENG":"This might be just a simulation, but I do not think you should have that kind of mindset in battle.","TWN":"雖然只是模擬戰，但在下認為在戰鬥中不能有那樣的心態。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_MAGICIAN_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L38_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"최대한 효율적인 방법을 고안하여 적을 처치하는 것이 중요하지 않겠소?","JPN":"最大限効率的な方法を考案し、敵を撃退することが重要ではないでしょうか。","ENG":"Is it not better to come up with the most effective method to defeat the enemy?","TWN":"想出最有效的方法來消滅敵人不是很重要嗎？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_MAGICIAN_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"방금 전투는 모두의 힘이 있었기에 가능했던 것이오.","JPN":"先程の戦闘は皆の力があったからこそ勝利したのです。","ENG":"That battle was only possible because everyone worked together.","TWN":"剛才的戰鬥能成功，全靠大家的力量。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_MAGICIAN_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"나이엘도, 나도, 혼자서는 불가능했을 것이오.","JPN":"ナイエルも、自分も、1人だったら敵わなかったでしょう。","ENG":"It wouldn't have been possible if I or you, Naielle, were alone.","TWN":"無論是奈爾還是在下，單憑一己之力都是不可能的。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_MAGICIAN_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NULL","text":{"KOREA":"하아? 지금 날 얕잡아 보는 거야?","JPN":"はあ？　私をバカにしてるわけ？","ENG":"Huh? Are you saying that I'm weak?","TWN":"蛤？你現在是在小看我嗎？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"BORA_PROMISE_NULL_NULL","text":{"KOREA":"싸우면 안 돼……. 친구끼리.","JPN":"ケンカはよくない……友だちだから。","ENG":"Don't fight... between friends.","TWN":"不能吵架……朋友之間。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORA_PROMISE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L45_1","type":"dialog","speaker":"BORA_PROMISE_NULL_NULL","text":{"KOREA":"여기까지야……. 오늘은.","JPN":"ここまでだよ……今日は。","ENG":"Class is dismissed... for today.","TWN":"到此為止吧……今天。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORA_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};